            return Task.CompletedTask;
        }

        private Task OnTransitionEndAsync(TransitionEventArgs args)
        {
            // Only handle the collapse animation (grid-template-rows), not transitions from child elements
            if (!string.Equals(args.PropertyName, "grid-template-rows", StringComparison.Ordinal))
            {
                return Task.CompletedTask;
            }

            if (_state == CollapseState.Entering)
            {
                _state = CollapseState.Entered;
                StateHasChanged();
            }
            else if (_state == CollapseState.Exiting)
            {
                _state = CollapseState.Exited;
                StateHasChanged();
            }

            return OnAnimationEnd.InvokeAsync(_expandedState.Value);
        }
    }
}

